input:
interface BaseManifest {
  author: 'input' | 'output' | 'bidirectional';
  tags: number;
  active?: 'pending' | 'active' | 'done';
  error: string;
  required?: number;
  enabled: boolean;
  state: string | null;
}

output:
BaseManifest
  = author:AuthorSection EOL tags:TagsSection EOL error:ErrorSection EOL enabled:EnabledSection EOL state:StateSection active:ActiveOpt required:RequiredOpt EOLopt
    { return { author: author, tags: tags, error: error, enabled: enabled, state: state, active: active, required: required }; }

AuthorSection
  = "AUTHOR:" _ v:("input" / "output" / "bidirectional") { return v; }

TagsSection
  = "TAGS:" _ v:Float { return v; }

ErrorSection
  = "ERROR:" _ v:QuotedString { return v; }

EnabledSection
  = "ENABLED:" _ v:Bool { return v; }

StateSection
  = "STATE:" _ "none" { return null; }
  / "STATE:" _ v:QuotedString { return v; }

ActiveOpt
  = EOL "ACTIVE:" _ v:("pending" / "active" / "done") { return v; }
  / "" { return undefined; }

RequiredOpt
  = EOL "REQUIRED:" _ v:Integer { return v; }
  / "" { return undefined; }

Bool = "yes" { return true; } / "no" { return false; }
QuotedString = '"' chars:$[^"]* '"' { return chars; }
Float = chars:$([0-9]+ ("." [0-9]+)?) { return parseFloat(chars); }
Integer = chars:$[0-9]+ { return parseInt(chars, 10); }
_ = [ \t]*
EOL = _ "\n"
EOLopt = (_ "\n")?

