  timeout: boolean;
  destination: string[];
  height: number;
  expiresAt: 'text' | 'code' | 'error' | 'tool-output';
}

output:
CoreOutput
  = summary:SummarySection EOL timeout:TimeoutSection EOL destination:DestinationSection EOL height:HeightSection EOL expiresAt:ExpiresAtSection EOLopt
    { return { summary: summary, timeout: timeout, destination: destination, height: height, expiresAt: expiresAt }; }

SummarySection
  = "SUMMARY:" _ v:("continue" / "replan" / "escalate") { return v; }

TimeoutSection
  = "TIMEOUT:" _ v:Bool { return v; }

DestinationSection
  = "DESTINATION:" _ "none" { return []; }
  / "DESTINATION:" _ first:Identifier rest:("," _ id:Identifier { return id; })* { return [first, ...rest]; }

HeightSection
  = "HEIGHT:" _ v:Integer { return v; }

ExpiresAtSection
  = "EXPIRES_AT:" _ v:("text" / "code" / "error" / "tool-output") { return v; }

Bool = "yes" { return true; } / "no" { return false; }
Identifier = chars:$[a-zA-Z0-9_-]+ { return chars; }
QuotedString = '"' chars:$[^"]* '"' { return chars; }
Integer = chars:$[0-9]+ { return parseInt(chars, 10); }
_ = [ \t]*
EOL = _ "\n"
EOLopt = (_ "\n")?

