  creator: 'observation' | 'action' | 'result' | 'goal' | 'constraint';
  limit: string;
  kind?: 'capacity' | 'ttl' | 'manual';
  summary: string;
  source?: number;
  labels?: number;
  weight?: string;
}

output:
RawStatus
  = creator:CreatorSection EOL limit:LimitSection EOL summary:SummarySection kind:KindOpt source:SourceOpt labels:LabelsOpt weight:WeightOpt EOLopt
    { return { creator: creator, limit: limit, summary: summary, kind: kind, source: source, labels: labels, weight: weight }; }

CreatorSection
  = "CREATOR:" _ v:("observation" / "action" / "result" / "goal" / "constraint") { return v; }

LimitSection
  = "LIMIT:" _ v:QuotedString { return v; }

SummarySection
  = "SUMMARY:" _ v:QuotedString { return v; }

KindOpt
  = EOL "KIND:" _ v:("capacity" / "ttl" / "manual") { return v; }
  / "" { return undefined; }

SourceOpt
  = EOL "SOURCE:" _ v:Float { return v; }
  / "" { return undefined; }

LabelsOpt
  = EOL "LABELS:" _ v:Float { return v; }
  / "" { return undefined; }

WeightOpt
  = EOL "WEIGHT:" _ v:QuotedString { return v; }
  / "" { return undefined; }

QuotedString = '"' chars:$[^"]* '"' { return chars; }
Float = chars:$([0-9]+ ("." [0-9]+)?) { return parseFloat(chars); }
_ = [ \t]*
EOL = _ "\n"
EOLopt = (_ "\n")?

input:
interface Response {
