}

output:
Response
  = priority:PrioritySection EOL cause:CauseSection EOL interval:IntervalSection EOL summary:SummarySection EOLopt
    { return { priority: priority, cause: cause, interval: interval, summary: summary }; }

PrioritySection
  = "PRIORITY:" _ v:Bool { return v; }

CauseSection
  = "CAUSE:" _ v:Bool { return v; }

IntervalSection
  = "INTERVAL:" _ v:Float { return v; }

SummarySection
  = "SUMMARY:" _ v:QuotedString { return v; }

Bool = "yes" { return true; } / "no" { return false; }
QuotedString = '"' chars:$[^"]* '"' { return chars; }
Float = chars:$([0-9]+ ("." [0-9]+)?) { return parseFloat(chars); }
_ = [ \t]*
EOL = _ "\n"
EOLopt = (_ "\n")?

input:
interface Record {
  timestamp: string[];
  creator?: string;
  limit: 'queued' | 'running' | 'completed' | 'failed';
}

output:
Record
  = timestamp:TimestampSection EOL limit:LimitSection creator:CreatorOpt EOLopt
    { return { timestamp: timestamp, limit: limit, creator: creator }; }

TimestampSection
  = "TIMESTAMP:" _ "none" { return []; }
  / "TIMESTAMP:" _ first:Identifier rest:("," _ id:Identifier { return id; })* { return [first, ...rest]; }

LimitSection
  = "LIMIT:" _ v:("queued" / "running" / "completed" / "failed") { return v; }

CreatorOpt
  = EOL "CREATOR:" _ v:QuotedString { return v; }
  / "" { return undefined; }

Identifier = chars:$[a-zA-Z0-9_-]+ { return chars; }
QuotedString = '"' chars:$[^"]* '"' { return chars; }
_ = [ \t]*
EOL = _ "\n"
EOLopt = (_ "\n")?

